import { Component, OnInit } from '@angular/core';
import { ChessAgentService } from '../../services/chess-agent.service';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})
export class DashboardComponent implements OnInit {
  currentFen: string = 'rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1';
  aiAnalysis: string = "Posez une question ou jouez un coup pour commencer.";
  userInput: string = "";
  isLoading: boolean = false;
  errorMessage: string = "";

  // Configuration de l'échiquier
  boardOptions = {
    drawDisabled: false, // Autorise le mouvement des pièces
    responsive: true,
    light: '#d2d2d2',
    dark: '#587391'
  };

  constructor(private chessAgentService: ChessAgentService) {}

  ngOnInit(): void {}

  // Cette méthode est appelée automatiquement lors du lâcher d'une pièce
  onMove(event: any) {
    this.currentFen = event.fen;
    this.isLoading = true;

    this.chessAgentService.analyzePosition(this.currentFen).subscribe({
      next: (response: any) => {
        this.aiAnalysis = response.analysis || "Aucune analyse disponible.";
        this.isLoading = false;
      },
      error: (err) => {
        this.errorMessage = "Erreur lors de l'analyse IA.";
        this.isLoading = false;
      }
    });
  }

  sendChatMessage() {
    if (!this.userInput.trim()) return;

    this.isLoading = true;
    this.chessAgentService.sendChat
        Message(this.userInput).subscribe({
      next: (response: any) => {
        this.aiAnalysis = response.reply;
        this.userInput = "";
        this.isLoading = false;
      },
      error: () => {
        this.errorMessage = "Impossible de contacter l'assistant.";
        this.isLoading = false;
      }
    });
  }
}
